from openai import OpenAI
import json

client = OpenAI()

tools = [
    {
        "type": "function",
        "function": {
            "name": "read_file",
            "description": "Read the contents of a file",
            "parameters": {
                "type": "object",
                "properties": {"path": {"type": "string"}},
                "required": ["path"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "write_file",
            "description": "Write content to a file",
            "parameters": {
                "type": "object",
                "properties": {
                    "path": {"type": "string"},
                    "content": {"type": "string"},
                },
                "required": ["path", "content"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "run_python",
            "description": "Execute a Python snippet and return stdout",
            "parameters": {
                "type": "object",
                "properties": {"code": {"type": "string"}},
                "required": ["code"],
            },
        },
    },
]

def dispatch_tool(name: str, args: dict) -> str:
    if name == "read_file":
        try:
            return open(args["path"]).read()
        except FileNotFoundError:
            return f"Error: file not found: {args['path']}"
    elif name == "write_file":
        open(args["path"], "w").write(args["content"])
        return f"Written {len(args['content'])} bytes to {args['path']}"
    elif name == "run_python":
        import subprocess, sys
        result = subprocess.run([sys.executable, "-c", args["code"]],
                                capture_output=True, text=True, timeout=10)
        return result.stdout or result.stderr
    return json.dumps({"error": f"unknown tool: {name}"})

def run_task_agent(task: str, max_steps: int = 20) -> str:
    messages = [
        {"role": "system", "content":
            "You are a task-completion agent. Complete the given task step by step "
            "using the available tools. When finished, output ONLY the final result."},
        {"role": "user", "content": task},
    ]
    for step in range(max_steps):
        response = client.chat.completions.create(
            model="gpt-4o", messages=messages, tools=tools, tool_choice="auto"
        )
        msg = response.choices[0].message

        if not msg.tool_calls:
            # No more tool calls — task complete
            return msg.content

        # Execute all tool calls in this step
        messages.append(msg)
        for tc in msg.tool_calls:
            result = dispatch_tool(tc.function.name, json.loads(tc.function.arguments))
            messages.append({"role": "tool", "tool_call_id": tc.id, "content": result})

    return "Max steps reached — task incomplete"

# Example usage
result = run_task_agent(
    "Read requirements.txt, generate a one-paragraph plain-language description "
    "of what this project does based on its dependencies, and write it to README_summary.txt"
)
print(result)

from enum import Enum
from dataclasses import dataclass, field

class AgentState(Enum):
    PLANNING   = "planning"
    EXECUTING  = "executing"
    VERIFYING  = "verifying"
    RETRYING   = "retrying"
    COMPLETE   = "complete"
    FAILED     = "failed"

@dataclass
class TaskContext:
    task: str
    plan: list[str] = field(default_factory=list)
    current_step: int = 0
    artifacts: dict = field(default_factory=dict)   # intermediate results
    errors: list[str] = field(default_factory=list)
    state: AgentState = AgentState.PLANNING
    retry_count: int = 0
    max_retries: int = 3

def run_state_machine(task: str) -> str:
    ctx = TaskContext(task=task)

    while ctx.state not in (AgentState.COMPLETE, AgentState.FAILED):
        if ctx.state == AgentState.PLANNING:
            ctx.plan = generate_plan(ctx.task)
            ctx.state = AgentState.EXECUTING

        elif ctx.state == AgentState.EXECUTING:
            if ctx.current_step >= len(ctx.plan):
                ctx.state = AgentState.VERIFYING
                continue
            step = ctx.plan[ctx.current_step]
            success, output = execute_step_with_tools(step, ctx.artifacts)
            if success:
                ctx.artifacts[f"step_{ctx.current_step}"] = output
                ctx.current_step += 1
            else:
                ctx.errors.append(f"Step {ctx.current_step}: {output}")
                ctx.state = AgentState.RETRYING

        elif ctx.state == AgentState.VERIFYING:
            passed = verify(ctx.task, ctx.artifacts)
            ctx.state = AgentState.COMPLETE if passed else AgentState.RETRYING

        elif ctx.state == AgentState.RETRYING:
            ctx.retry_count += 1
            if ctx.retry_count > ctx.max_retries:
                ctx.state = AgentState.FAILED
            else:
                ctx.state = AgentState.EXECUTING   # re-attempt current step

    return (ctx.artifacts.get(f"step_{ctx.current_step - 1}", "no output")
            if ctx.state == AgentState.COMPLETE else f"FAILED: {ctx.errors}")

